import{_ as n,o as t,c as a,ae as i}from"./chunks/framework.BuvKvcPh.js";const s="/Furniture-Designer/images/design-en.png",h=JSON.parse('{"title":"3D Design & Modeling","description":"","frontmatter":{},"headers":[],"relativePath":"design.md","filePath":"design.md"}'),o={name:"design.md"};function r(l,e,c,d,u,m){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_3d-design-modeling" tabindex="-1">3D Design &amp; Modeling <a class="header-anchor" href="#_3d-design-modeling" aria-label="Permalink to &quot;3D Design &amp; Modeling&quot;">​</a></h1><p>The <strong>Furniture Designer</strong> centers around a recursive space-partitioning design paradigm. Instead of drawing individual boards on a canvas, you define functional volumes, and the algorithmic geometry solves the board intersections and thicknesses itself. This ensures your furniture remains mathematically perfect and physically structurally viable at all times.</p><p><img src="'+s+'" alt="Design Interface"></p><h2 id="global-constraints" tabindex="-1">Global Constraints <a class="header-anchor" href="#global-constraints" aria-label="Permalink to &quot;Global Constraints&quot;">​</a></h2><p>Your design starts by defining the absolute maximum bounds of the cabinet:</p><ul><li><strong>Outer Dimensions</strong>: The total outer bounding box width, height, and depth.</li><li><strong>Material Thickness</strong>: Wood thickness applied uniformly across all boards. Change it, and all inner compartments dynamically recalculate to compensate.</li></ul><h2 id="creating-compartments" tabindex="-1">Creating Compartments <a class="header-anchor" href="#creating-compartments" aria-label="Permalink to &quot;Creating Compartments&quot;">​</a></h2><p>By selecting any 3D node (either clicking on the 3D model directly, or selecting it via the left-hand hierarchy tree), you can split the space sequentially:</p><ul><li><strong>Rows (Horizontal Dividers)</strong>: Slices the available vertical space.</li><li><strong>Columns (Vertical Dividers)</strong>: Slices the available horizontal space.</li></ul><p>You can nest columns inside rows inside columns infinitely.</p><h2 id="advanced-dimension-controls" tabindex="-1">Advanced Dimension Controls <a class="header-anchor" href="#advanced-dimension-controls" aria-label="Permalink to &quot;Advanced Dimension Controls&quot;">​</a></h2><p>When a node is subdivided, the inner space is divided by the separating planks. By default, the remaining space is distributed evenly.</p><ul><li><strong>Locking Absolute Dimensions 🔒</strong>: You can lock the dimension of any compartment (in millimeters) to ensure it does not resize dynamically. This is crucial when designing a niche for an amplifier that must be exactly 430mm wide.</li><li><strong>Equalize Sizes ⚖</strong>: If you have added or removed a compartment, hit &quot;Equalize&quot; to fairly redistribute all remaining unlocked space among your compartments instantly.</li><li><strong>Resize Stealing</strong>: If you manually resize an unlocked compartment, the software automatically &quot;steals&quot; space from its closest unlocked neighbor, ensuring the outer dimensions of your furniture never break.</li></ul><h2 id="overlays-reference-objects" tabindex="-1">Overlays &amp; Reference Objects <a class="header-anchor" href="#overlays-reference-objects" aria-label="Permalink to &quot;Overlays &amp; Reference Objects&quot;">​</a></h2><p>The UI provides powerful overlay tools:</p><ul><li><strong>Quotes</strong>: Toggle absolute measurements on the 3D view.</li><li><strong>Locks</strong>: Visually highlights which compartments have rigid dimensions.</li><li><strong>Objects</strong>: Spawn scaled 3D reference objects into your compartments (e.g., a <strong>55&quot; TV</strong>, an <strong>Xbox Series X</strong>, a <strong>Vinyl Record Turntable</strong>, or an <strong>IKEA Kallax Basket</strong>). These mockups assure you that your stuff will actually fit!</li></ul>',16)])])}const p=n(o,[["render",r]]);export{h as __pageData,p as default};
